import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';

export default function FigmaLogin() {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const { login } = useAuth();
    const navigate = useNavigate();

    const handleSubmit = async (e) => {
        e.preventDefault();
        const success = await login(email, password);
        if (success) navigate('/');
    };

    return (
        <div className="input_form-214">
            <div className="logo-203"><div className="rectangle-982-204"></div></div>
            <form onSubmit={handleSubmit}>
                <div className="property-1-default" style={{ marginBottom: '15px' }}>
                    <input type="email" placeholder="Email" value={email} onChange={e => setEmail(e.target.value)} style={{ background: 'transparent', border: 'none', color: 'white', flex: 1, outline: 'none' }} required />
                </div>
                <div className="property-1-default" style={{ marginBottom: '25px' }}>
                    <input type="password" placeholder="Пароль" value={password} onChange={e => setPassword(e.target.value)} style={{ background: 'transparent', border: 'none', color: 'white', flex: 1, outline: 'none' }} required />
                </div>
                <div className="property-1-default" onClick={handleSubmit}><p className="text-224">Войти</p></div>
            </form>
            <p style={{ textAlign: 'center', marginTop: '20px', color: '#999' }}>Нет аккаунта? <Link to="/register" style={{ color: '#8B5CF6' }}>Регистрация</Link></p>
        </div>
    );
}
